import React, { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { useNavigate, Link } from "react-router";
import axiosClient from "../utility/axios";
import logo from "../assets/logo.png";
import { Loader2, Package, Tag, FileText, Image as ImageIcon, LayoutList, Hash, CheckCircle, AlertCircle } from "lucide-react";

// Matches backend product expectations
const productSchema = z.object({
  name: z.string().min(1, "Product name is required"),
  price: z.coerce.number().min(0, "Price cannot be negative"),
  description: z.string().min(1, "Description is required"),
  image: z.string().url("Must be a valid image URL"),
  category: z.enum(["Electronics", "Instrument", "Stationary", "Other"], { errorMap: () => ({ message: "Please select a valid category" }) }),
  stock: z.coerce.number().min(0, "Stock cannot be negative").int("Stock must be a whole number"),
});

export default function AddProduct() {
  const [apiError, setApiError] = useState("");
  const [successMsg, setSuccessMsg] = useState("");
  const [loading, setLoading] = useState(false);
  
  const navigate = useNavigate();

  const {
    register,
    handleSubmit,
    reset,
    formState: { errors },
  } = useForm({
    resolver: zodResolver(productSchema),
    defaultValues: {
      name: "",
      price: "",
      description: "",
      image: "",
      category: "",
      stock: "",
    },
  });

  const onSubmit = async (data) => {
    setLoading(true);
    setApiError("");
    setSuccessMsg("");

    try {
      const response = await axiosClient.post("/product/createproduct", data);
      setSuccessMsg(response.data.message || "Product created successfully!");
      reset(); // clear form
    } catch (err) {
      setApiError(err.response?.data?.message || err.message || "Failed to create product");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-r from-indigo-900 via-purple-900 to-slate-900 flex flex-col font-sans text-slate-800">
      {/* Simple Header */}
      <nav className="bg-white border-b border-slate-200 px-6 py-4 flex justify-between items-center relative z-10 shadow-sm">
        <Link to="/" className="flex items-center gap-2 group decoration-transparent">
          <img src={logo} alt="StoodoMart Logo" className="w-8 h-auto" />
          <span className="text-xl font-extrabold tracking-tight text-slate-800">Stoodo<span className="text-indigo-600">Mart</span></span>
        </Link>
        <Link to="/profile" className="text-sm font-semibold text-slate-500 hover:text-indigo-600 transition-colors">
          Back to Profile
        </Link>
      </nav>

      {/* Main Form Content */}
      <main className="flex-grow flex justify-center items-start py-10 px-4 sm:px-6">
        <div className="w-full max-w-2xl bg-white rounded-2xl shadow-md border border-slate-200 overflow-hidden">
          
          <div className="px-8 py-6 border-b border-slate-100 bg-slate-50/50">
            <h1 className="text-2xl font-bold text-slate-800 mb-1">Add New Product</h1>
            <p className="text-sm text-slate-500">Fill out the details below to add a product to the catalog.</p>
          </div>

          <div className="p-8">
            {apiError && (
              <div className="mb-6 p-4 rounded-xl bg-red-50 border border-red-200 text-red-700 text-sm flex items-center gap-3">
                <AlertCircle size={18} className="shrink-0" />
                <span>{apiError}</span>
              </div>
            )}

            {successMsg && (
              <div className="mb-6 p-4 rounded-xl bg-green-50 border border-green-200 text-green-700 text-sm flex items-center gap-3">
                <CheckCircle size={18} className="shrink-0" />
                <span>{successMsg}</span>
              </div>
            )}

            <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
              
              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700 ml-1">Product Name *</label>
                <div className="relative">
                  <Package className="absolute left-4 top-1/2 transform -translate-y-1/2 text-slate-400 w-5 h-5 pointer-events-none" />
                  <input
                    type="text"
                    {...register("name")}
                    className="w-full pl-11 pr-4 py-3 bg-white border border-slate-300 rounded-xl text-slate-800 placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-100 focus:border-indigo-400 transition-all shadow-sm"
                    placeholder="e.g. Wireless Headphones"
                  />
                </div>
                {errors.name && <p className="text-red-500 text-xs ml-1 font-medium">{errors.name.message}</p>}
              </div>
              
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700 ml-1">Price (Γé╣) *</label>
                  <div className="relative">
                    <Tag className="absolute left-4 top-1/2 transform -translate-y-1/2 text-slate-400 w-5 h-5 pointer-events-none" />
                    <input
                      type="number"
                      step="0.01"
                      {...register("price")}
                      className="w-full pl-11 pr-4 py-3 bg-white border border-slate-300 rounded-xl text-slate-800 placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-100 focus:border-indigo-400 transition-all shadow-sm"
                      placeholder="0.00"
                    />
                  </div>
                  {errors.price && <p className="text-red-500 text-xs ml-1 font-medium">{errors.price.message}</p>}
                </div>

                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700 ml-1">Stock Quantity *</label>
                  <div className="relative">
                    <Hash className="absolute left-4 top-1/2 transform -translate-y-1/2 text-slate-400 w-5 h-5 pointer-events-none" />
                    <input
                      type="number"
                      {...register("stock")}
                      className="w-full pl-11 pr-4 py-3 bg-white border border-slate-300 rounded-xl text-slate-800 placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-100 focus:border-indigo-400 transition-all shadow-sm"
                      placeholder="e.g. 50"
                    />
                  </div>
                  {errors.stock && <p className="text-red-500 text-xs ml-1 font-medium">{errors.stock.message}</p>}
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700 ml-1">Category *</label>
                <div className="relative">
                  <LayoutList className="absolute left-4 top-1/2 transform -translate-y-1/2 text-slate-400 w-5 h-5 pointer-events-none" />
                  <select
                    {...register("category")}
                    defaultValue=""
                    className="w-full pl-11 pr-4 py-3 bg-white border border-slate-300 rounded-xl text-slate-800 focus:outline-none focus:ring-2 focus:ring-indigo-100 focus:border-indigo-400 transition-all shadow-sm appearance-none cursor-pointer"
                  >
                    <option value="" disabled>Select a category</option>
                    <option value="Electronics">Electronics</option>
                    <option value="Instrument">Instrument</option>
                    <option value="Stationary">Stationary</option>
                    <option value="Other">Other</option>
                  </select>
                </div>
                {errors.category && <p className="text-red-500 text-xs ml-1 font-medium">{errors.category.message}</p>}
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700 ml-1">Image URL *</label>
                <div className="relative">
                  <ImageIcon className="absolute left-4 top-1/2 transform -translate-y-1/2 text-slate-400 w-5 h-5 pointer-events-none" />
                  <input
                    type="url"
                    {...register("image")}
                    className="w-full pl-11 pr-4 py-3 bg-white border border-slate-300 rounded-xl text-slate-800 placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-100 focus:border-indigo-400 transition-all shadow-sm"
                    placeholder="https://example.com/image.png"
                  />
                </div>
                {errors.image && <p className="text-red-500 text-xs ml-1 font-medium">{errors.image.message}</p>}
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700 ml-1">Description *</label>
                <div className="relative">
                  <FileText className="absolute left-4 top-4 text-slate-400 w-5 h-5 pointer-events-none" />
                  <textarea
                    {...register("description")}
                    rows="4"
                    className="w-full pl-11 pr-4 py-3 bg-white border border-slate-300 rounded-xl text-slate-800 placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-100 focus:border-indigo-400 transition-all shadow-sm resize-none"
                    placeholder="Describe the product details..."
                  />
                </div>
                {errors.description && <p className="text-red-500 text-xs ml-1 font-medium">{errors.description.message}</p>}
              </div>

              <div className="pt-4 flex items-center justify-end gap-4 border-t border-slate-100">
                <Link
                  to="/profile"
                  className="px-6 py-3 bg-white border border-slate-300 hover:bg-slate-50 text-slate-700 font-bold rounded-xl transition-all"
                >
                  Cancel
                </Link>
                <button
                  type="submit"
                  disabled={loading}
                  className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl shadow-md shadow-indigo-200 transition-all active:scale-95 disabled:opacity-70 disabled:cursor-not-allowed flex items-center gap-2 min-w-[170px] justify-center"
                >
                  {loading ? (
                    <div className="flex gap-2 items-center">
                      <div className="w-1.5 h-1.5 rounded-full bg-white animate-pulse"></div>
                      <div className="w-1.5 h-1.5 rounded-full bg-white animate-pulse delay-75"></div>
                      <div className="w-1.5 h-1.5 rounded-full bg-white animate-pulse delay-150"></div>
                      <span className="ml-1">Creating...</span>
                    </div>
                  ) : "Create Product"}
                </button>
              </div>

            </form>
          </div>
        </div>
      </main>
    </div>
  );
}

import React, { useState, useEffect, useCallback } from "react";
import { Link, useNavigate } from "react-router";
import axiosClient from "../utility/axios";
import { Search, Edit2, Trash2, ShieldAlert, ChevronLeft, ChevronRight, User } from "lucide-react";
import logo from "../assets/logo.png";
import { useSelector } from "react-redux";

export default function AllProfiles() {
  const [profiles, setProfiles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [searchTerm, setSearchTerm] = useState("");
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const { user } = useSelector((state) => state.auth);
  const navigate = useNavigate();

  const fetchProfiles = useCallback(async () => {
    setLoading(true);
    setError("");
    try {
      const res = await axiosClient.get("/person/supergetAllProfile", {
        params: { page, limit: 10, email: searchTerm },
      });
      setProfiles(res.data.person || []);
      setTotalPages(res.data.totalPages || 1);
    } catch (err) {
      if (err.response?.status === 404) {
          setProfiles([]);
          setTotalPages(1);
      } else {
          setError(err.response?.data?.message || "Failed to fetch profiles");
          setProfiles([]);
      }
    } finally {
      setLoading(false);
    }
  }, [page, searchTerm]);

  useEffect(() => {
    const delayDebounceFn = setTimeout(() => {
      fetchProfiles();
    }, 500);
    return () => clearTimeout(delayDebounceFn);
  }, [searchTerm, page, fetchProfiles]);

  const handleDelete = async (id) => {
    if (!window.confirm("Are you sure you want to delete this profile?")) return;
    try {
      await axiosClient.delete(`/person/superdeleteprofile/${id}`);
      fetchProfiles();
    } catch (err) {
      alert(err.response?.data?.message || "Failed to delete profile");
    }
  };

  return (
    <div className="min-h-screen font-sans flex flex-col relative overflow-hidden bg-slate-800 bg-gradient-to-br from-indigo-500/40 via-purple-500/40 to-slate-800/40">
      
      {/* Navbar Integration */}
      <nav className="relative z-20 px-8 py-5 border-b border-white/20 flex items-center justify-between w-full bg-white/10 backdrop-blur-md">
        <Link to="/" className="flex items-center gap-3 group">
          <div className="bg-white/10 p-2 rounded-xl backdrop-blur-md transition-all duration-300 group-hover:bg-white/20 group-hover:scale-105 shadow-sm">
            <img src={logo} alt="StoodoMart Logo" className="w-8 h-auto transform group-hover:-rotate-6 transition-transform duration-300" />
          </div>
          <h1 className="text-xl font-extrabold tracking-tight text-white drop-shadow-md">
            Stoodo<span className="text-purple-400">Mart</span>
          </h1>
        </Link>
        
        <div className="flex items-center gap-6">
          <div className="relative w-72 group">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-300 w-5 h-5 transition-colors group-focus-within:text-purple-400" />
            <input
              type="text"
              placeholder="Search by email..."
              value={searchTerm}
              onChange={(e) => {
                setSearchTerm(e.target.value);
                setPage(1);
              }}
              className="w-full pl-10 pr-4 py-2 bg-slate-900/40 border border-slate-500/50 rounded-xl text-sm focus:ring-2 focus:ring-purple-400/50 outline-none transition-all duration-300 text-white placeholder-slate-400 hover:border-slate-400 focus:border-purple-400"
            />
          </div>
          <Link
            to="/profile"
            className="flex items-center gap-2 px-5 py-2 rounded-xl text-sm font-bold bg-white/10 text-white hover:bg-white/20 transition-all backdrop-blur-md active:scale-95 border border-white/10 shadow-lg"
          >
            <User size={18} />
            <span>Profile Info</span>
          </Link>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="relative z-10 flex-1 p-8 max-w-7xl mx-auto w-full">
        {/* Header and Error */}
        <div className="mb-6 flex items-center justify-between">
            <h2 className="text-3xl font-extrabold text-white drop-shadow-md">User Directory</h2>
        </div>
        
        {error && (
          <div className="mb-6 p-4 rounded-xl bg-red-500/20 border border-red-500/50 text-red-100 flex items-center gap-3 backdrop-blur-sm">
            <ShieldAlert size={20} />
            <span className="font-medium">{error}</span>
          </div>
        )}

        {/* Loading / List */}
        {loading ? (
          <div className="bg-white/10 backdrop-blur-xl border border-white/20 rounded-[2rem] shadow-[0_20px_50px_rgba(0,0,0,0.3)] p-6 overflow-hidden">
             <div className="animate-pulse flex flex-col gap-6">
                 {/* Table Header Skeleton */}
                 <div className="flex gap-4 items-center w-full pb-4 border-b border-white/10">
                     <div className="h-6 bg-white/20 rounded w-1/4"></div>
                     <div className="h-6 bg-white/20 rounded w-1/4"></div>
                     <div className="h-6 bg-white/20 rounded w-1/6 ml-auto"></div>
                 </div>
                 {/* Rows Skeleton */}
                 {[1, 2, 3, 4, 5].map(i => (
                    <div key={i} className="flex gap-6 items-center w-full py-2">
                       <div className="w-10 h-10 bg-white/20 rounded-full flex-shrink-0"></div>
                       <div className="h-5 bg-white/20 rounded w-1/4"></div>
                       <div className="h-5 bg-white/20 rounded w-1/4"></div>
                       <div className="h-8 bg-white/20 rounded-xl w-20 ml-auto mr-4"></div>
                    </div>
                 ))}
             </div>
          </div>
        ) : profiles.length === 0 ? (
          <div className="text-center py-20 text-slate-300 bg-white/10 backdrop-blur-xl border border-white/20 rounded-[2rem] shadow-[0_20px_50px_rgba(0,0,0,0.3)]">
            <User size={56} className="mx-auto mb-4 opacity-50 text-indigo-300" />
            <p className="text-xl font-medium">No profiles found.</p>
          </div>
        ) : (
          <div className="bg-white/10 backdrop-blur-xl border border-white/20 rounded-[2rem] shadow-[0_20px_50px_rgba(0,0,0,0.3)] overflow-hidden transform transition-all duration-300 hover:shadow-[0_20px_50px_rgba(0,0,0,0.4)]">
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-white/5 border-b border-white/10 text-slate-300 text-sm">
                    <th className="py-5 px-6 font-bold uppercase tracking-wider">Name</th>
                    <th className="py-5 px-6 font-bold uppercase tracking-wider">Email</th>
                    <th className="py-5 px-6 font-bold uppercase tracking-wider">Role</th>
                    <th className="py-5 px-6 font-bold uppercase tracking-wider text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-white/10">
                  {profiles.map((profile) => (
                    <tr key={profile._id} className="group hover:bg-white/10 transition-all duration-300 ease-in-out cursor-default">
                      <td className="py-4 px-6 text-white">
                        <div className="flex items-center gap-4">
                            <div className="w-12 h-12 rounded-full bg-gradient-to-br from-indigo-500 to-purple-600 shadow-inner group-hover:from-indigo-400 group-hover:to-purple-500 flex items-center justify-center font-bold text-lg text-white transition-colors duration-300 border border-white/20">
                                {(profile.firstname?.[0] || 'U').toUpperCase()}
                            </div>
                            <span className="font-bold text-white tracking-wide text-lg drop-shadow-sm">
                              {profile.firstname} {profile.lastname}
                            </span>
                        </div>
                      </td>
                      <td className="py-4 px-6 text-slate-200 font-medium tracking-wide">{profile.email}</td>
                      <td className="py-4 px-6">
                        <span className={`px-4 py-1.5 text-xs font-bold rounded-full shadow-sm transition-all duration-300 border backdrop-blur-md ${
                          profile.role === 'SuperAdmin' ? 'bg-purple-500/20 text-purple-200 border-purple-400/50' :
                          profile.role === 'Admin' ? 'bg-blue-500/20 text-blue-200 border-blue-400/50' :
                          'bg-slate-500/20 text-slate-200 border-slate-400/50'
                        }`}>
                          {profile.role || 'User'}
                        </span>
                      </td>
                      <td className="py-4 px-6 text-right">
                        <div className="flex items-center justify-end gap-3 opacity-70 group-hover:opacity-100 transition-opacity duration-300">
                          <Link
                            to={`/superadmin/update-profile/${profile._id}`}
                            className="p-2 text-indigo-300 hover:text-white bg-indigo-500/10 hover:bg-indigo-500/40 border border-transparent hover:border-indigo-400/50 rounded-xl transition-all duration-300 hover:scale-105 hover:shadow-lg"
                            title="Update Profile"
                          >
                            <Edit2 size={20} />
                          </Link>
                          {user?._id !== profile._id && (
                            <button
                              onClick={() => handleDelete(profile._id)}
                              className="p-2 text-red-400 hover:text-white bg-red-500/10 hover:bg-red-500/60 border border-transparent hover:border-red-400/50 rounded-xl transition-all duration-300 hover:scale-105 hover:shadow-lg"
                              title="Delete Profile"
                            >
                              <Trash2 size={20} />
                            </button>
                          )}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            {/* Pagination */}
            {totalPages > 1 && (
              <div className="p-5 border-t border-white/10 flex items-center justify-between text-sm text-slate-200 bg-white/5">
                <div className="font-medium bg-white/10 px-4 py-1.5 rounded-full border border-white/10">
                  Page <span className="font-bold text-white">{page}</span> of <span className="font-bold text-white">{totalPages}</span>
                </div>
                <div className="flex items-center gap-3">
                  <button
                    onClick={() => setPage(p => Math.max(1, p - 1))}
                    disabled={page === 1}
                    className="p-2.5 rounded-xl border border-white/20 bg-white/10 hover:bg-white/20 text-white disabled:opacity-30 disabled:hover:bg-white/10 disabled:cursor-not-allowed transition-all shadow-sm active:scale-95"
                  >
                    <ChevronLeft size={18} />
                  </button>
                  <button
                    onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                    disabled={page === totalPages}
                    className="p-2.5 rounded-xl border border-white/20 bg-white/10 hover:bg-white/20 text-white disabled:opacity-30 disabled:hover:bg-white/10 disabled:cursor-not-allowed transition-all shadow-sm active:scale-95"
                  >
                    <ChevronRight size={18} />
                  </button>
                </div>
              </div>
            )}
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate } from 'react-router';
import { RegisterUser } from '../Authslice';
import logo from '../assets/logo.png';

// Define the validation schema using Zod
const signupSchema = z.object({
  firstname: z.string().min(2, 'First name must be at least 2 characters'),
  lastname: z.string().min(2, 'Last name must be at least 2 characters'),
  email: z.string().min(1, 'Email is required').email('Invalid email address'),
  password: z.string().min(6, 'Password must be at least 6 characters'),
  confirmPassword: z.string().min(1, 'Confirm password is required'),
}).refine((data) => data.password === data.confirmPassword, {
  path: ['confirmPassword'],
  message: "Passwords don't match",
});

export default function Signup() {
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  
  const dispatch = useDispatch();
  const { loading, error, isAuthenticated } = useSelector((state) => state.auth);
  const navigate = useNavigate();

  // Redirect to home if successfully registered & authenticated
  useEffect(() => {
    if (isAuthenticated) {
      navigate('/');
    }
  }, [isAuthenticated, navigate]);

  const {
    register,
    handleSubmit,
    formState: { errors, isSubmitting },
  } = useForm({
    resolver: zodResolver(signupSchema),
    defaultValues: {
      firstname: '',
      lastname: '',
      email: '',
      password: '',
      confirmPassword: '',
    },
  });

  const onSubmit = (data) => {
    // Exclude confirmPassword and append a default role if needed by backend.
    const { confirmPassword, ...registerData } = data;
    registerData.role = 'User'; // Default role (adjust if your backend expects something else)
    
    dispatch(RegisterUser(registerData));
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-mesh-gradient animate-gradient-bg p-8 overflow-hidden relative before:content-[''] before:absolute before:rounded-full before:blur-[80px] before:z-0 before:opacity-60 before:w-[400px] before:h-[400px] before:bg-brand-teal before:-top-[100px] before:-left-[100px] before:animate-float after:content-[''] after:absolute after:rounded-full after:blur-[80px] after:z-0 after:opacity-60 after:w-[500px] after:h-[500px] after:bg-brand-red after:-bottom-[150px] after:-right-[100px] after:animate-float-reverse">
      <div className="relative z-10 bg-white/85 backdrop-blur-md border border-white/40 rounded-3xl p-8 sm:p-12 w-full max-w-[500px] shadow-2xl opacity-0 translate-y-[30px] animate-slide-up my-8">
        
        <div className="flex flex-col items-center mb-6">
          <img src={logo} alt="StoodoMart Logo" className="w-16 h-auto mb-3 drop-shadow-md transition-transform duration-300 hover:scale-105 hover:-rotate-3" />
          <h1 className="text-2xl font-extrabold text-[#1a1a2e] m-0 tracking-tight">Stoodo<span className="text-brand-red">Mart</span></h1>
        </div>
        
        <p className="text-center text-slate-500 text-[0.95rem] mb-6">Create your account to get started.</p>

        {error && (
          <div className="mb-6 p-4 bg-red-100 text-red-700 rounded-xl text-sm font-medium border border-red-200">
            {typeof error === 'string' ? error : error?.message || 'Registration failed'}
          </div>
        )}

        <form onSubmit={handleSubmit(onSubmit)} className="signup-form">
          <div className="grid grid-cols-2 gap-4 mb-5">
            <div className="relative group">
              <label htmlFor="firstname" className="block text-sm font-semibold text-slate-700 mb-1.5 transition-colors duration-300 group-focus-within:text-[#00B4DB]">First Name</label>
              <input 
                type="text" 
                id="firstname"
                className={`w-full px-4 py-3 text-base text-slate-800 bg-white/90 border-2 rounded-xl outline-none transition-all duration-300 placeholder:text-slate-400 focus:ring-4 focus:bg-white ${
                  errors.firstname ? 'border-red-500 focus:border-red-500 focus:ring-red-500/15' : 'border-slate-200 focus:border-brand-teal focus:ring-brand-teal/15'
                }`}
                placeholder="Rishabh"
                {...register('firstname')}
              />
              {errors.firstname && (
                <p className="mt-1 text-xs text-red-500 font-medium">{errors.firstname.message}</p>
              )}
            </div>

            <div className="relative group">
              <label htmlFor="lastname" className="block text-sm font-semibold text-slate-700 mb-1.5 transition-colors duration-300 group-focus-within:text-[#00B4DB]">Last Name</label>
              <input 
                type="text" 
                id="lastname"
                className={`w-full px-4 py-3 text-base text-slate-800 bg-white/90 border-2 rounded-xl outline-none transition-all duration-300 placeholder:text-slate-400 focus:ring-4 focus:bg-white ${
                  errors.lastname ? 'border-red-500 focus:border-red-500 focus:ring-red-500/15' : 'border-slate-200 focus:border-brand-teal focus:ring-brand-teal/15'
                }`}
                placeholder="Singh"
                {...register('lastname')}
              />
              {errors.lastname && (
                <p className="mt-1 text-xs text-red-500 font-medium">{errors.lastname.message}</p>
              )}
            </div>
          </div>

          <div className="mb-5 relative group">
            <label htmlFor="email" className="block text-sm font-semibold text-slate-700 mb-1.5 transition-colors duration-300 group-focus-within:text-[#00B4DB]">Email address</label>
            <input 
              type="email" 
              id="email"
              className={`w-full px-4 py-3 text-base text-slate-800 bg-white/90 border-2 rounded-xl outline-none transition-all duration-300 placeholder:text-slate-400 focus:ring-4 focus:bg-white ${
                errors.email ? 'border-red-500 focus:border-red-500 focus:ring-red-500/15' : 'border-slate-200 focus:border-brand-teal focus:ring-brand-teal/15'
              }`}
              placeholder="rishabh@example.com"
              {...register('email')}
            />
            {errors.email && (
              <p className="mt-1 text-xs text-red-500 font-medium">{errors.email.message}</p>
            )}
          </div>

          <div className="mb-5 relative group">
            <label htmlFor="password" className="block text-sm font-semibold text-slate-700 mb-1.5 transition-colors duration-300 group-focus-within:text-[#00B4DB]">Password</label>
            <div className="relative">
              <input 
                type={showPassword ? "text" : "password"} 
                id="password"
                className={`w-full px-4 py-3 text-base text-slate-800 bg-white/90 border-2 rounded-xl outline-none transition-all duration-300 placeholder:text-slate-400 focus:ring-4 focus:bg-white pr-10 ${
                  errors.password ? 'border-red-500 focus:border-red-500 focus:ring-red-500/15' : 'border-slate-200 focus:border-brand-teal focus:ring-brand-teal/15'
                }`}
                placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                {...register('password')}
              />
              <button 
                type="button"
                className="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-400 hover:text-brand-teal transition-colors focus:outline-none"
                onClick={() => setShowPassword(!showPassword)}
                aria-label={showPassword ? "Hide password" : "Show password"}
              >
                {showPassword ? (
                  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M3.98 8.223A10.477 10.477 0 0 0 1.934 12C3.226 16.338 7.244 19.5 12 19.5c.993 0 1.953-.138 2.863-.395M6.228 6.228A10.451 10.451 0 0 1 12 4.5c4.756 0 8.773 3.162 10.065 7.498a10.522 10.522 0 0 1-4.293 5.774M6.228 6.228 3 3m3.228 3.228 3.65 3.65m7.894 7.894L21 21m-3.228-3.228-3.65-3.65m0 0a3 3 0 1 0-4.243-4.243m4.242 4.242L9.88 9.88" />
                  </svg>
                ) : (
                  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M2.036 12.322a1.012 1.012 0 0 1 0-.639C3.423 7.51 7.36 4.5 12 4.5c4.638 0 8.573 3.007 9.963 7.178.07.207.07.431 0 .639C20.577 16.49 16.64 19.5 12 19.5c-4.638 0-8.573-3.007-9.963-7.178Z" />
                    <path strokeLinecap="round" strokeLinejoin="round" d="M15 12a3 3 0 1 1-6 0 3 3 0 0 1 6 0Z" />
                  </svg>
                )}
              </button>
            </div>
            {errors.password && (
              <p className="mt-1 text-xs text-red-500 font-medium">{errors.password.message}</p>
            )}
          </div>

          <div className="mb-8 relative group">
            <label htmlFor="confirmPassword" className="block text-sm font-semibold text-slate-700 mb-1.5 transition-colors duration-300 group-focus-within:text-[#00B4DB]">Confirm Password</label>
            <div className="relative">
              <input 
                type={showConfirmPassword ? "text" : "password"} 
                id="confirmPassword"
                className={`w-full px-4 py-3 text-base text-slate-800 bg-white/90 border-2 rounded-xl outline-none transition-all duration-300 placeholder:text-slate-400 focus:ring-4 focus:bg-white pr-10 ${
                  errors.confirmPassword ? 'border-red-500 focus:border-red-500 focus:ring-red-500/15' : 'border-slate-200 focus:border-brand-teal focus:ring-brand-teal/15'
                }`}
                placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                {...register('confirmPassword')}
              />
              <button 
                type="button"
                className="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-400 hover:text-brand-teal transition-colors focus:outline-none"
                onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                aria-label={showConfirmPassword ? "Hide confirm password" : "Show confirm password"}
              >
                {showConfirmPassword ? (
                  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M3.98 8.223A10.477 10.477 0 0 0 1.934 12C3.226 16.338 7.244 19.5 12 19.5c.993 0 1.953-.138 2.863-.395M6.228 6.228A10.451 10.451 0 0 1 12 4.5c4.756 0 8.773 3.162 10.065 7.498a10.522 10.522 0 0 1-4.293 5.774M6.228 6.228 3 3m3.228 3.228 3.65 3.65m7.894 7.894L21 21m-3.228-3.228-3.65-3.65m0 0a3 3 0 1 0-4.243-4.243m4.242 4.242L9.88 9.88" />
                  </svg>
                ) : (
                  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M2.036 12.322a1.012 1.012 0 0 1 0-.639C3.423 7.51 7.36 4.5 12 4.5c4.638 0 8.573 3.007 9.963 7.178.07.207.07.431 0 .639C20.577 16.49 16.64 19.5 12 19.5c-4.638 0-8.573-3.007-9.963-7.178Z" />
                    <path strokeLinecap="round" strokeLinejoin="round" d="M15 12a3 3 0 1 1-6 0 3 3 0 0 1 6 0Z" />
                  </svg>
                )}
              </button>
            </div>
            {errors.confirmPassword && (
              <p className="mt-1 text-xs text-red-500 font-medium">{errors.confirmPassword.message}</p>
            )}
          </div>

          <button 
            type="submit" 
            disabled={loading || isSubmitting}
            className="w-full p-3.5 text-base font-bold text-white bg-gradient-to-br from-brand-red to-brand-orange border-none rounded-xl cursor-pointer transition-all duration-300 shadow-[0_4px_15px_rgba(255,75,43,0.4)] relative overflow-hidden hover:-translate-y-0.5 hover:shadow-[0_8px_25px_rgba(255,75,43,0.5)] active:translate-y-[1px] disabled:opacity-70 disabled:cursor-not-allowed after:content-[''] after:absolute after:top-0 after:-left-full after:w-full after:h-full after:bg-gradient-to-r after:from-transparent after:via-white/20 after:to-transparent after:transition-all after:duration-500 hover:after:left-full flex justify-center items-center"
          >
            {loading ? (
              <div className="flex gap-2 items-center">
                <div className="w-2 h-2 rounded-full bg-white animate-pulse"></div>
                <div className="w-2 h-2 rounded-full bg-white animate-pulse delay-75"></div>
                <div className="w-2 h-2 rounded-full bg-white animate-pulse delay-150"></div>
              </div>
            ) : 'Create Account'}
          </button>
        </form>

        <div className="mt-8 text-center text-[0.95rem] text-slate-600">
          Already have an account? 
          <a href="/login" className="font-bold text-brand-red no-underline ml-2 relative after:content-[''] after:absolute after:w-full after:h-[2px] after:-bottom-[2px] after:left-0 after:bg-brand-red after:scale-x-0 after:origin-bottom-right after:transition-transform after:duration-300 hover:after:scale-x-100 hover:after:origin-bottom-left">Log in</a>
        </div>
        
      </div>
    </div>
  );
}
